// ---------- types.ts ----------
type Currency = string;

interface CartItem {
  id: string;
  sku?: string;
  quantity: number;
  unitPrice: number; // in smallest currency unit (e.g., cents)
  metadata?: Record<string, any>;
}

interface Cart {
  items: CartItem[];
  shippingCost?: number;
  currency: Currency;
  metadata?: Record<string, any>;
}

interface EvaluationContext {
  cart: Cart;
  customer?: { id?: string; segment?: string; attributes?: Record<string, any> };
  channel?: string;
  now?: Date;
  // any other runtime signals
}

// AppliedPromotion and AppliedBenefit follow your schema
type BenefitType = 'percentage' | 'fixed' | 'freeProduct' | 'shipping' | 'gift';

interface AppliedBenefit {
  type: BenefitType;
  value?: number; // percent (0-100) for percentage, amount in smallest unit for fixed, or shipping amount
  targetItemId?: string; // which cart item it targeted
  freeProductId?: string;
  freeProductQuantity?: number;
  description?: string;
}

interface AppliedPromotion {
  promotionId: string;
  promotionCode?: string;
  appliedBenefits: AppliedBenefit[];
  totalDiscountAmount: number; // in smallest currency unit
  message?: string;
}

// Rule/action interfaces
interface Rule {
  id: string;
  name: string;
  promotionCode?: string;
  enabled: boolean;
  priority: number;
  startAt?: Date;
  endAt?: Date;
  usageLimit?: number; // optional cap
  createdAt?: Date;
  predicate: (ctx: EvaluationContext) => boolean;
  actions: Action[];
  metadata?: Record<string, any>;
}

interface Action {
  type: string;
  // evaluate returns AppliedBenefit[] (do not sum or cap here; engine will handle caps)
  evaluate: (ctx: EvaluationContext) => AppliedBenefit[];
}

// ---------- rule-engine.ts ----------
class RuleEngine {
  private rules: Map<string, Rule> = new Map();

  registerRule(rule: Rule) {
    if (!rule.id) throw new Error('Rule must have id');
    this.rules.set(rule.id, { ...rule, createdAt: rule.createdAt ?? new Date() });
  }

  removeRule(ruleId: string) {
    this.rules.delete(ruleId);
  }

  listRules() {
    return Array.from(this.rules.values());
  }

  evaluate(ctx: EvaluationContext): AppliedPromotion[] {
    const now = ctx.now ?? new Date();
    // Step 1: select applicable rules
    let candidates = Array.from(this.rules.values())
      .filter(r => r.enabled)
      .filter(r => (r.startAt ? r.startAt <= now : true) && (r.endAt ? r.endAt >= now : true));

    // Step 2: sort by priority (desc) then createdAt (asc)
    candidates.sort((a, b) => {
      if (b.priority !== a.priority) return b.priority - a.priority;
      return (a.createdAt?.getTime() ?? 0) - (b.createdAt?.getTime() ?? 0);
    });

    // Maintain per-item running totals to enforce caps (not to exceed item price)
    const itemDiscountAccumulator: Map<string, number> = new Map(); // itemId -> amount discounted so far

    const results: AppliedPromotion[] = [];

    for (const rule of candidates) {
      try {
        if (!rule.predicate(ctx)) continue;

        // Execute actions to produce benefits
        const benefits: AppliedBenefit[] = [];
        for (const action of rule.actions) {
          const b = action.evaluate(ctx) || [];
          for (const ben of b) {
            // Normalize benefit shape: if fixed discount and targetItemId exists, ensure not negative or overcap
            if ((ben.type === 'fixed' || ben.type === 'shipping' || ben.type === 'percentage') && ben.targetItemId) {
              // compute discount amount for this benefit to allow capping
              let computedAmount = 0;
              const targetItem = ctx.cart.items.find(i => i.id === ben.targetItemId);
              if (!targetItem) continue; // skip invalid target
              if (ben.type === 'percentage' && ben.value != null) {
                computedAmount = Math.floor((targetItem.unitPrice * targetItem.quantity) * (ben.value / 100));
              } else if (ben.type === 'fixed' && ben.value != null) {
                computedAmount = ben.value;
              } else if (ben.type === 'shipping' && ben.value != null) {
                computedAmount = ben.value;
              }
              const acc = itemDiscountAccumulator.get(targetItem.id) ?? 0;
              // cap to not exceed total item price
              const remainingCap = Math.max(0, targetItem.unitPrice * targetItem.quantity - acc);
              const appliedAmount = Math.min(remainingCap, computedAmount);
              if (appliedAmount <= 0) continue;
              // if percentage benefit was truncated, rewrite ben.value to reflect actual applied amount for downstream reporting
              if (ben.type === 'percentage') {
                // convert back to effective percent for description (optional)
                // keep ben.value as original percent but we track amount in totals
              }
              // record applied amount in a metadata field on benefit (not in schema — we will use description to record) 
              ben.description = ben.description ?? `${ben.type} applied: ${appliedAmount}`;
              // track accumulator
              itemDiscountAccumulator.set(targetItem.id, acc + appliedAmount);
              // attach computed numeric discount as a special marker in description (we'll compute totals below)
              (ben as any).__computedAmount = appliedAmount;
            } else if (ben.type === 'freeProduct' && ben.freeProductId) {
              // free product: treat as zero cost addition; handled by creating benefit with quantity
              // For free product no capping needed
            }
            benefits.push(ben);
          }
        }

        // Compute totalDiscountAmount for this promotion by summing computed amounts
        let totalDiscount = 0;
        for (const ben of benefits) {
          const amt = (ben as any).__computedAmount;
          if (typeof amt === 'number') totalDiscount += amt;
          else if (ben.type === 'freeProduct' && ben.freeProductId && ben.freeProductQuantity) {
            // free product: attempt to estimate value if metadata available (skip in pilot)
            // For pilot keep zero or optionally compute approximate from a price lookup
          }
        }

        if (benefits.length === 0) continue; // nothing applied

        const applied: AppliedPromotion = {
          promotionId: rule.id,
          promotionCode: rule.promotionCode,
          appliedBenefits: benefits.map(b => {
            // strip internal __computedAmount from output; keep numeric info embedded in description
            const copy: AppliedBenefit = { ...b };
            // Optionally add computedAmount in description for audit
            if ((b as any).__computedAmount != null) {
              copy.description = (copy.description ?? '') + ` (computedDiscount=${(b as any).__computedAmount})`;
            }
            // remove any internal props
            delete (copy as any).__computedAmount;
            return copy;
          }),
          totalDiscountAmount: totalDiscount,
          message: `Rule '${rule.name}' applied${rule.promotionCode ? ` (${rule.promotionCode})` : ''}`,
        };

        results.push(applied);
      } catch (err) {
        // Pilot: swallow rule failures but log them
        console.error(`RuleEngine: error evaluating rule ${rule.id}:`, err);
        // optionally record a diagnostic "failed" AppliedPromotion (not applied) for debugging
      }
    }

    return results;
  }
}

